#!/usr/bin/env node
/**
 * Manual test script for mittwald_cronjob_execution_get tool
 *
 * This script demonstrates testing the tool with sample inputs
 */

import Anthropic from '@anthropic-ai/sdk';

const MCP_SERVER_URL = process.env.MCP_SERVER_URL || 'https://mittwald-mcp-fly2.fly.dev/mcp';

async function testCronjobExecutionGet() {
  console.log('Testing mittwald_cronjob_execution_get tool...\n');

  // Step 1: First, we need to list cronjobs to get valid IDs
  console.log('Step 1: Getting list of cronjobs...');

  try {
    const client = new Anthropic({
      apiKey: process.env.ANTHROPIC_API_KEY,
    });

    // First, let's try to get a list of projects to find a project ID
    console.log('\nAttempting to list projects to find a valid project context...');

    const projectListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_project_list tool to list all projects. Return the project IDs in your response.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_project_list',
        description: 'List all projects',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('\nProject list response:');
    console.log(JSON.stringify(projectListMessage, null, 2));

    // Now try to list cronjobs for a project
    console.log('\n\nStep 2: Attempting to list cronjobs...');

    const cronjobListMessage = await client.messages.create({
      model: 'claude-3-5-sonnet-20241022',
      max_tokens: 4096,
      messages: [{
        role: 'user',
        content: 'Use the mittwald_cronjob_list tool to list all cronjobs. Return the cronjob IDs in your response.'
      }],
      tools: [{
        type: 'custom',
        name: 'mcp__mittwald__mittwald_cronjob_list',
        description: 'List cronjobs',
        input_schema: {
          type: 'object',
          properties: {},
        }
      }]
    });

    console.log('\nCronjob list response:');
    console.log(JSON.stringify(cronjobListMessage, null, 2));

  } catch (error) {
    console.error('Error during test:', error);
    if (error instanceof Error) {
      console.error('Error message:', error.message);
      console.error('Error stack:', error.stack);
    }
  }
}

// Run the test
testCronjobExecutionGet().catch(console.error);

/**
 * Discovery - Static Tool Inventory (T035, T036)
 *
 * IMPORTANT: This module uses a STATIC tool list derived from source code.
 * DO NOT make direct HTTP calls to the MCP server - only spawned Claude Code
 * subprocesses have MCP authentication configured.
 *
 * The test harness provides the tool list; the LLM agents execute the tools.
 */

import type { DiscoveredTool, DiscoveryOptions } from '../types/index.js';
import { getStaticTools, STATIC_TOOL_NAMES, STATIC_TOOL_COUNT } from './static-tools.js';

/**
 * Tools to exclude from inventory (security/multi-tenancy)
 * These are already excluded in static-tools.ts but kept here for reference
 */
const EXCLUDED_TOOLS = [
  'mcp__mittwald__mittwald_login_reset',
  'mcp__mittwald__mittwald_login_token',
];

/**
 * Parse MCP tool name to display format
 * mcp__mittwald__mittwald_project_create → project/create
 */
export function parseToolName(mcpName: string): string {
  // Remove mcp__mittwald__ prefix
  const withoutPrefix = mcpName.replace(/^mcp__mittwald__mittwald_/, '');

  // Replace underscores with slashes for category/action format
  // Handle patterns like: project_create → project/create
  // database_mysql_create → database/mysql/create
  const parts = withoutPrefix.split('_');

  if (parts.length === 1) {
    return parts[0];
  }

  // First part is category, rest are action path
  return parts.join('/');
}

/**
 * Check if tool should be excluded
 */
export function isExcludedTool(name: string): boolean {
  return EXCLUDED_TOOLS.includes(name);
}

/**
 * Discover tools from static inventory (T035)
 *
 * This uses a static list derived from source code rather than
 * calling the MCP server. Only Claude Code subprocesses have
 * MCP authentication - the harness itself cannot call MCP.
 *
 * @param _options Discovery options (unused - kept for API compatibility)
 * @returns Array of discovered tools from static inventory
 */
export async function discover(_options?: DiscoveryOptions): Promise<DiscoveredTool[]> {
  // Return static tool list - no HTTP calls needed
  return getStaticTools();
}

/**
 * Get display name for a tool
 */
export function getDisplayName(mcpName: string): string {
  return parseToolName(mcpName);
}

/**
 * Default MCP server URL (used by Claude Code subprocess, not by harness)
 */
export const DEFAULT_MCP_SERVER_URL = 'https://mittwald-mcp-fly2.fly.dev/mcp';

/**
 * Get all static tool names
 */
export function getAllToolNames(): readonly string[] {
  return STATIC_TOOL_NAMES;
}

/**
 * Get total tool count
 */
export function getToolCount(): number {
  return STATIC_TOOL_COUNT;
}

