     1→/**
     2→ * MCP Functional Test Harness - Main Entry Point
     3→ *
     4→ * Orchestrates functional testing of ~174 MCP tools deployed on Fly.io.
     5→ * Implements T042-T051: orchestration, queue, concurrency, integration.
     6→ */
     7→
     8→import type {
     9→  TestExecutionOptions,
    10→  TestSuiteResult,
    11→  CoordinatorStatus,
    12→  TestQueueItem,
    13→  ToolEntry,
    14→  TestDomain,
    15→  ManifestEntry,
    16→  CleanupResult,
    17→  SessionResult,
    18→  SpawnSessionOptions,
    19→  CoordinatorInput,
    20→} from '../types/index.js';
    21→import { SessionRunner } from './session-runner.js';
    22→import { Coordinator } from './coordinator.js';
    23→import { ManifestManager } from './manifest.js';
    24→import { createToolManifest, type ToolManifest, DEFAULT_MCP_SERVER_URL, loadTestDomainsConfig } from '../inventory/index.js';
    25→import { createResourceTracker, type ResourceTracker, type TestContext } from '../resources/tracker.js';
    26→import { cleanupDomain, findOrphans, cleanupOrphans, type OrphanResource } from '../resources/cleanup.js';
    27→import { generateUniqueName } from '../resources/naming.js';
    28→import { getDomainsInOrder } from '../inventory/grouping.js';
    29→
    30→/**
    31→ * Harness version for manifest entries
    32→ */
    33→export const HARNESS_VERSION = '1.0.0';
    34→
    35→/**
    36→ * Default concurrency limit (FR-003)
    37→ */
    38→const DEFAULT_CONCURRENCY = 5;
    39→
    40→/**
    41→ * Polling interval for async operations in ms (30 seconds per spec)
    42→ */
    43→const POLLING_INTERVAL_MS = 30000;
    44→
    45→/**
    46→ * Max polling attempts
    47→ */
    48→const MAX_POLL_ATTEMPTS = 10;
    49→
    50→/**
    51→ * Consistency window for eventual consistency retry (30 seconds)
    52→ */
    53→const CONSISTENCY_WINDOW_MS = 30000;
    54→
    55→// ============================================================================
    56→// Session Pool - Concurrency Control (T044)
    57→// ============================================================================
    58→
    59→/**
    60→ * Semaphore-based session pool for concurrency control
    61→ */
    62→class SessionPool {
    63→  private available: number;
    64→  private waiting: Array<() => void> = [];
    65→  private activeSessions: Set<string> = new Set();
    66→
    67→  constructor(maxConcurrency: number) {
    68→    this.available = maxConcurrency;
    69→  }
    70→
    71→  /**
    72→   * Acquire a session slot
    73→   */
    74→  async acquire(): Promise<void> {
    75→    if (this.available > 0) {
    76→      this.available--;
    77→      return;
    78→    }
    79→    await new Promise<void>((resolve) => this.waiting.push(resolve));
    80→  }
    81→
    82→  /**
    83→   * Release a session slot
    84→   */
    85→  release(): void {
    86→    const next = this.waiting.shift();
    87→    if (next) {
    88→      next();
    89→    } else {
    90→      this.available++;
    91→    }
    92→  }
    93→
    94→  /**
    95→   * Track an active session
    96→   */
    97→  trackSession(sessionId: string): void {
    98→    this.activeSessions.add(sessionId);
    99→  }
   100→
   101→  /**
   102→   * Untrack a completed session
   103→   */
   104→  untrackSession(sessionId: string): void {
   105→    this.activeSessions.delete(sessionId);
   106→  }
   107→
   108→  /**
   109→   * Get number of active sessions
   110→   */
   111→  getActiveCount(): number {
   112→    return this.activeSessions.size;
   113→  }
   114→
   115→  /**
   116→   * Wait for all sessions to complete
   117→   */
   118→  async drain(): Promise<void> {
   119→    while (this.activeSessions.size > 0) {
   120→      await sleep(100);
   121→    }
   122→  }
   123→}
   124→
   125→// ============================================================================
   126→// Utility Functions
   127→// ============================================================================
   128→
   129→/**
   130→ * Sleep for a given duration
   131→ */
   132→function sleep(ms: number): Promise<void> {
   133→  return new Promise((resolve) => setTimeout(resolve, ms));
   134→}
   135→
   136→/**
   137→ * Check if error is a rate limit error (T048)
   138→ */
   139→function isRateLimited(error: unknown): boolean {
   140→  if (error instanceof Error) {
   141→    const msg = error.message.toLowerCase();
   142→    return msg.includes('429') || msg.includes('rate limit') || msg.includes('too many requests');
   143→  }
   144→  return false;
   145→}
   146→
   147→/**
   148→ * Check if error is a consistency error (T049)
   149→ */
   150→function isConsistencyError(error: unknown): boolean {
   151→  if (error instanceof Error) {
   152→    const msg = error.message.toLowerCase();
   153→    return msg.includes('404') || msg.includes('403') || msg.includes('not found');
   154→  }
   155→  return false;
   156→}
   157→
   158→/**
   159→ * Retry with exponential backoff for rate limits (T048)
   160→ */
   161→async function withRateLimitRetry<T>(fn: () => Promise<T>, maxRetries: number = 5): Promise<T> {
   162→  let delay = 1000;
   163→  for (let i = 0; i < maxRetries; i++) {
   164→    try {
   165→      return await fn();
   166→    } catch (e) {
   167→      if (isRateLimited(e) && i < maxRetries - 1) {
   168→        console.warn(`[harness] Rate limited, retrying in ${delay}ms...`);
   169→        await sleep(delay);
   170→        delay *= 2;
   171→        continue;
   172→      }
   173→      throw e;
   174→    }
   175→  }
   176→  throw new Error('Rate limit exceeded after retries');
   177→}
   178→
   179→/**
   180→ * Retry with consistency window (T049)
   181→ */
   182→async function withConsistencyRetry<T>(fn: () => Promise<T>, maxWaitMs: number = CONSISTENCY_WINDOW_MS): Promise<T> {
   183→  const start = Date.now();
   184→  let lastError: Error | undefined;
   185→
   186→  while (Date.now() - start < maxWaitMs) {
   187→    try {
   188→      return await fn();
   189→    } catch (e) {
   190→      if (isConsistencyError(e)) {
   191→        lastError = e instanceof Error ? e : new Error(String(e));
   192→        await sleep(1000);
   193→        continue;
   194→      }
   195→      throw e;
   196→    }
   197→  }
   198→
   199→  throw lastError || new Error('Resource not available after consistency window');
   200→}
   201→
   202→/**
   203→ * Poll for completion (T046)
   204→ */
   205→async function pollForCompletion(
   206→  checkFn: () => Promise<boolean>,
   207→  intervalMs: number = POLLING_INTERVAL_MS,
   208→  maxAttempts: number = MAX_POLL_ATTEMPTS
   209→): Promise<boolean> {
   210→  for (let i = 0; i < maxAttempts; i++) {
   211→    if (await checkFn()) {
   212→      return true;
   213→    }
   214→    console.log(`[harness] Polling attempt ${i + 1}/${maxAttempts}, waiting ${intervalMs}ms...`);
   215→    await sleep(intervalMs);
   216→  }
   217→  return false;
   218→}
   219→
   220→// ============================================================================
   221→// Test Queue Management (T043)
   222→// ============================================================================
   223→
   224→/**
   225→ * Build prioritized test queue from inventory
   226→ */
   227→function buildTestQueue(inventory: ToolManifest, options?: TestExecutionOptions): TestQueueItem[] {
   228→  const queue: TestQueueItem[] = [];
   229→  const entries = inventory.getAllEntries();
   230→
   231→  // Filter by options
   232→  let filteredEntries = entries;
   233→
   234→  if (options?.tools && options.tools.length > 0) {
   235→    const toolSet = new Set(options.tools);
   236→    filteredEntries = filteredEntries.filter((e) => toolSet.has(e.name) || toolSet.has(e.displayName));
   237→  }
   238→
   239→  if (options?.domains && options.domains.length > 0) {
   240→    const domainSet = new Set(options.domains);
   241→    filteredEntries = filteredEntries.filter((e) => domainSet.has(e.domain));
   242→  }
   243→
   244→  // Group by tier and domain
   245→  const byTier = new Map<number, ToolEntry[]>();
   246→  for (const entry of filteredEntries) {
   247→    const tier = entry.tier;
   248→    if (!byTier.has(tier)) {
   249→      byTier.set(tier, []);
   250→    }
   251→    byTier.get(tier)!.push(entry);
   252→  }
   253→
   254→  // Build queue in priority order: Tier 0, 1, 2, 3, 4
   255→  for (const tier of [0, 1, 2, 3, 4]) {
   256→    const tierEntries = byTier.get(tier) || [];
   257→
   258→    // Sort by domain within tier for grouping
   259→    tierEntries.sort((a, b) => a.domain.localeCompare(b.domain));
   260→
   261→    for (const entry of tierEntries) {
   262→      queue.push({
   263→        tool: entry,
   264→        priority: tier * 100 + (entry.cleanRoomRequired ? 0 : 1),
   265→        prerequisites: entry.prerequisites || [],
   266→        addedAt: new Date(),
   267→      });
   268→    }
   269→  }
   270→
   271→  return queue;
   272→}
   273→
   274→// ============================================================================
   275→// Test Execution (T045, T047)
   276→// ============================================================================
   277→
   278→/**
   279→ * Build test prompt for a tool
   280→ * Includes guidance for polling and eventual consistency (FR-013, FR-013c)
   281→ */
   282→function buildTestPrompt(tool: ToolEntry, context: TestContext): string {
   283→  const basePrompt = `You are testing the MCP tool "${tool.displayName}" (${tool.name}).
   284→
   285→Your task:
   286→1. Call the tool with appropriate parameters
   287→2. Verify the response is valid
   288→3. Report SUCCESS if the tool works correctly, FAILURE if it doesn't
   289→
   290→Tool description: ${tool.description || 'No description available'}
   291→
   292→IMPORTANT - Eventual Consistency and Polling (FR-013, FR-013c):
   293→- After write operations (create, update, delete), resources may take up to 30 seconds to propagate.
   294→- If you get a 404 or 403 error immediately after creating a resource, wait a few seconds and retry.
   295→- For async operations, poll at 30-second intervals (up to 5 minutes) to confirm completion.
   296→- Rate limiting: If you see 429 errors, wait with exponential backoff before retrying.
   297→
   298→`;
   299→
   300→  if (context.mode === 'clean-room') {
   301→    return (
   302→      basePrompt +
   303→      `
   304→This is a CLEAN-ROOM test. You must discover all prerequisites yourself.
   305→Do not assume any pre-existing resources.
   306→`
   307→    );
   308→  }
   309→
   310→  // Harness-assisted mode
   311→  let contextInfo = 'Available resources:\n';
   312→  if (context.projectId) contextInfo += `- Project ID: ${context.projectId}\n`;
   313→  if (context.serverId) contextInfo += `- Server ID: ${context.serverId}\n`;
   314→  if (context.organizationId) contextInfo += `- Organization ID: ${context.organizationId}\n`;
   315→  if (context.databaseId) contextInfo += `- Database ID: ${context.databaseId}\n`;
   316→  if (context.appId) contextInfo += `- App ID: ${context.appId}\n`;
   317→
   318→  return basePrompt + contextInfo;
   319→}
   320→
   321→/**
   322→ * Setup test context based on tool requirements
   323→ */
   324→async function setupTestContext(tool: ToolEntry, tracker: ResourceTracker, sharedContext: SharedTestContext): Promise<TestContext> {
   325→  if (tool.cleanRoomRequired) {
   326→    return tracker.createCleanRoomContext();
   327→  }
   328→
   329→  // Harness-assisted mode - provide pre-created resources
   330→  return tracker.createHarnessAssistedContext({
   331→    projectId: sharedContext.projectId,
   332→    serverId: sharedContext.serverId,
   333→    organizationId: sharedContext.organizationId,
   334→  });
   335→}
   336→
   337→/**
   338→ * Shared context for harness-assisted tests (T034)
   339→ *
   340→ * Clean-room mode: Empty context, test agent discovers everything
   341→ * Harness-assisted mode: Harness creates prerequisites, passes IDs to agent
   342→ */
   343→interface SharedTestContext {
   344→  projectId?: string;
   345→  serverId?: string;
   346→  organizationId?: string;
   347→}
   348→
   349→/**
   350→ * Setup prerequisites for harness-assisted mode (T034)
   351→ * Creates shared resources that will be passed to test agents.
   352→ *
   353→ * Returns empty context for clean-room mode - ensuring no pre-created resources.
   354→ */
   355→async function setupDomainPrerequisites(
   356→  domain: TestDomain,
   357→  tracker: ResourceTracker,
   358→  cleanRoom: boolean
   359→): Promise<SharedTestContext> {
   360→  // Clean-room mode: Return empty context, enforcing no pre-created resources
   361→  if (cleanRoom) {
   362→    console.log(`[harness] Domain ${domain}: Clean-room mode - no prerequisites`);
   363→    return {};
   364→  }
   365→
   366→  console.log(`[harness] Domain ${domain}: Setting up harness-assisted prerequisites...`);
   367→  const context: SharedTestContext = {};
   368→
   369→  // For domains that need a project, we would create one here via MCP
   370→  // The project creation itself should be done via the harness's privileged access
   371→  // (not via the test agent) to avoid circular dependencies
   372→  //
   373→  // Example (requires MCP client integration):
   374→  // if (['apps', 'databases', 'containers'].includes(domain)) {
   375→  //   const projectName = generateUniqueName('project', domain);
   376→  //   const projectResult = await mcpClient.call('mittwald_project_create', { ... });
   377→  //   context.projectId = projectResult.projectId;
   378→  //   await tracker.track({
   379→  //     resourceId: context.projectId,
   380→  //     resourceType: 'project',
   381→  //     name: projectName,
   382→  //     domain,
   383→  //     sessionId: 'harness',
   384→  //     testId: 'prerequisites',
   385→  //   });
   386→  // }
   387→
   388→  // For MVP: Log that prerequisites would be created, but actual creation
   389→  // requires MCP client integration which is out of scope for initial implementation
   390→  console.log(`[harness] Domain ${domain}: Prerequisites setup complete (none required for MVP)`);
   391→
   392→  return context;
   393→}
   394→
   395→/**
   396→ * Test result for tracking pass/fail stats
   397→ */
   398→interface TestRunResult {
   399→  status: 'passed' | 'failed' | 'timeout' | 'interrupted';
   400→  testId: string;
   401→}
   402→
   403→/**
   404→ * Run a single test (T045, T047)
   405→ * Returns the test result status for tracking per-domain stats
   406→ */
   407→async function runTest(
   408→  test: TestQueueItem,
   409→  sessionRunner: SessionRunner,
   410→  coordinator: Coordinator,
   411→  manifest: ManifestManager,
   412→  tracker: ResourceTracker,
   413→  pool: SessionPool,
   414→  sharedContext: SharedTestContext,
   415→  domain: TestDomain
   416→): Promise<TestRunResult> {
   417→  const testId = `test-${test.tool.displayName.replace(/\//g, '-')}-${Date.now()}`;
   418→  let sessionId = '';
   419→  let status: 'passed' | 'failed' | 'timeout' | 'interrupted' = 'failed';
   420→  let errorMessage: string | undefined;
   421→  const startTime = Date.now();
   422→
   423→  try {
   424→    // Setup context
   425→    const context = await setupTestContext(test.tool, tracker, sharedContext);
   426→
   427→    // Build prompt
   428→    const prompt = buildTestPrompt(test.tool, context);
   429→
   430→    // Spawn session
   431→    const spawnOptions: SpawnSessionOptions = {
   432→      prompt,
   433→      workingDir: process.cwd(),
   434→      disallowedTools: ['Bash(mw)'],
   435→      // MCP server uses the global claude configuration, not a custom config
   436→      timeoutMs: 300000, // 5 minute timeout
   437→    };
   438→
   439→    const session = await sessionRunner.spawn(spawnOptions);
   440→    sessionId = session.sessionId;
   441→    pool.trackSession(sessionId);
   442→
   443→    console.log(`[harness] Started test ${testId} with session ${sessionId}`);
   444→
   445→    // Monitor with coordinator
   446→    let consecutiveErrors = 0;
   447→    let lastActivityTime = Date.now();
   448→    let sameToolCount = 0;
   449→    let lastTool = '';
   450→
   451→    for await (const event of session.stream) {
   452→      // Update activity time
   453→      lastActivityTime = Date.now();
   454→
   455→      // Track patterns for coordinator
   456→      if (event.type === 'error') {
   457→        consecutiveErrors++;
   458→      } else {
   459→        consecutiveErrors = 0;
   460→      }
   461→
   462→      if (event.type === 'tool_use') {
   463→        const toolName = (event.content as { tool?: string })?.tool || '';
   464→        if (toolName === lastTool) {
   465→          sameToolCount++;
   466→        } else {
   467→          sameToolCount = 1;
   468→          lastTool = toolName;
   469→        }
   470→      }
   471→
   472→      // Check with coordinator
   473→      const input: CoordinatorInput = {
   474→        sessionId,
   475→        testId,
   476→        toolUnderTest: test.tool.name,
   477→        recentOutput: [],
   478→        idleTimeMs: Date.now() - lastActivityTime,
   479→        patterns: {
   480→          consecutiveErrors,
   481→          retryAttempts: 0,
   482→          sameToolRepeated: sameToolCount,
   483→        },
   484→      };
   485→
   486→      const decision = await coordinator.analyze(input);
   487→
   488→      if (decision.action === 'terminate') {
   489→        console.warn(`[harness] Coordinator terminated session: ${decision.reason}`);
   490→        session.kill();
   491→        status = 'interrupted';
   492→        errorMessage = `Coordinator intervention: ${decision.reason}`;
   493→        break;
   494→      }
   495→    }
   496→
   497→    // Get final result
   498→    const result = await session.result;
   499→    status = result.status;
   500→    if (result.error) {
   501→      errorMessage = result.error;
   502→    }
   503→  } catch (err) {
   504→    // Record partial result on failure (T047)
   505→    status = 'failed';
   506→    errorMessage = err instanceof Error ? err.message : String(err);
   507→    console.error(`[harness] Test ${testId} failed:`, errorMessage);
   508→  } finally {
   509→    pool.untrackSession(sessionId);
   510→    pool.release();
   511→
   512→    const endTime = new Date();
   513→    const durationMs = Date.now() - startTime;
   514→
   515→    // Append to manifest (T050)
   516→    const entry: ManifestEntry = {
   517→      toolName: test.tool.name,
   518→      sessionId: sessionId || 'unknown',
   519→      testId,
   520→      status,
   521→      timestamp: endTime.toISOString(),
   522→      durationMs,
   523→      toolCallCount: 0,
   524→      errorMessage,
   525→      domain,
   526→      harnessVersion: HARNESS_VERSION,
   527→    };
   528→
   529→    try {
   530→      await manifest.append(entry);
   531→    } catch (appendErr) {
   532→      console.error(`[harness] Failed to append manifest entry:`, appendErr);
   533→    }
   534→
   535→    // Save session mapping (T059)
   536→    if (sessionId) {
   537→      await saveSessionMapping({
   538→        sessionId,
   539→        testId,
   540→        toolName: test.tool.name,
   541→        logPath: `~/.claude/projects/mcp-functional-tests/sessions/${sessionId}`,
   542→        startTime: new Date(startTime).toISOString(),
   543→        endTime: endTime.toISOString(),
   544→      });
   545→    }
   546→  }
   547→
   548→  return { status, testId };
   549→}
