   566→/**
   567→ * Run the full MCP functional test suite (T042)
   568→ */
   569→export async function runTestSuite(options?: TestExecutionOptions): Promise<TestSuiteResult> {
   570→  console.log('MCP Functional Test Harness v' + HARNESS_VERSION);
   571→  console.log('Options:', JSON.stringify(options, null, 2));
   572→
   573→  const startTime = new Date();
   574→  harnessState.currentPhase = 'initializing';
   575→
   576→  // Initialize components
   577→  const inventory = createToolManifest();
   578→  const manifest = new ManifestManager();
   579→  const coordinator = new Coordinator();
   580→  const tracker = createResourceTracker();
   581→  const sessionRunner = new SessionRunner();
   582→
   583→  // Discover tools
   584→  console.log('[harness] Discovering tools from MCP server...');
   585→  harnessState.currentPhase = 'discovery';
   586→  await withRateLimitRetry(() => inventory.discover({ serverUrl: options?.serverUrl || DEFAULT_MCP_SERVER_URL }));
   587→
   588→  const summary = inventory.getSummary();
   589→  console.log(`[harness] Discovered ${summary.totalTools} tools`);
   590→
   591→  // Build test queue
   592→  console.log('[harness] Building test queue...');
   593→  const queue = buildTestQueue(inventory, options);
   594→  harnessState.queuedTests = queue.length;
   595→  console.log(`[harness] ${queue.length} tests queued`);
   596→
   597→  // Initialize session pool
   598→  const concurrency = options?.concurrency ?? DEFAULT_CONCURRENCY;
   599→  const pool = new SessionPool(concurrency);
   600→  console.log(`[harness] Concurrency limit: ${concurrency}`);
   601→
   602→  // Shared context for harness-assisted tests
   603→  const sharedContext: SharedTestContext = {};
   604→
   605→  // Track domain completion and pass/fail stats
   606→  const domainTests = new Map<TestDomain, { total: number; completed: number; passed: number; failed: number }>();
   607→  const domainCleanupResults = new Map<TestDomain, CleanupResult>();
   608→
   609→  // Group tests by domain
   610→  for (const test of queue) {
   611→    const domain = test.tool.domain;
   612→    if (!domainTests.has(domain)) {
   613→      domainTests.set(domain, { total: 0, completed: 0, passed: 0, failed: 0 });
   614→    }
   615→    domainTests.get(domain)!.total++;
   616→  }
   617→
   618→  // Run tests
   619→  harnessState.currentPhase = 'testing';
   620→  const testPromises: Promise<void>[] = [];
   621→
   622→  for (const test of queue) {
   623→    // Acquire slot
   624→    await pool.acquire();
   625→
   626→    // Run test in background
   627→    const testPromise = runTest(test, sessionRunner, coordinator, manifest, tracker, pool, sharedContext, test.tool.domain)
   628→      .then((testResult) => {
   629→        harnessState.completedTests++;
   630→        const domainInfo = domainTests.get(test.tool.domain);
   631→        if (domainInfo) {
   632→          domainInfo.completed++;
   633→
   634→          // Track pass/fail per domain for accurate stats
   635→          if (testResult.status === 'passed') {
   636→            domainInfo.passed++;
   637→          } else {
   638→            domainInfo.failed++;
   639→            harnessState.failedTests++;
   640→          }
   641→
   642→          // Check if domain is complete (T051)
   643→          if (domainInfo.completed === domainInfo.total && !options?.skipCleanup) {
   644→            console.log(`[harness] Domain ${test.tool.domain} complete, running cleanup...`);
   645→            return cleanupDomain(tracker, test.tool.domain).then((result) => {
   646→              domainCleanupResults.set(test.tool.domain, result);
   647→              console.log(`[harness] Cleanup ${test.tool.domain}: ${result.cleaned}/${result.total} cleaned`);
   648→            });
   649→          }
   650→        }
   651→      })
   652→      .catch((err) => {
   653→        harnessState.failedTests++;
   654→        const domainInfo = domainTests.get(test.tool.domain);
   655→        if (domainInfo) {
   656→          domainInfo.completed++;
   657→          domainInfo.failed++;
   658→        }
   659→        console.error(`[harness] Test failed:`, err);
   660→      });
   661→
   662→    testPromises.push(testPromise);
   663→    harnessState.activeSessions = pool.getActiveCount();
   664→  }
   665→
   666→  // Wait for all tests to complete
   667→  console.log('[harness] Waiting for all tests to complete...');
   668→  await Promise.all(testPromises);
   669→  await pool.drain();
   670→
   671→  harnessState.currentPhase = 'complete';
   672→  const endTime = new Date();
   673→
   674→  // Build results
   675→  const coverage = await manifest.getCoverage();
   676→
   677→  const domainResults: Array<{
   678→    domain: string;
   679→    passed: number;
   680→    failed: number;
   681→    cleanup: CleanupResult;
   682→  }> = [];
   683→
   684→  for (const domain of getDomainsInOrder()) {
   685→    const cleanup = domainCleanupResults.get(domain) || {
   686→      domain,
   687→      total: 0,
   688→      cleaned: 0,
   689→      failed: 0,
   690→      failures: [],
   691→    };
   692→
   693→    // Get actual pass/fail stats from tracked domain data
   694→    const domainInfo = domainTests.get(domain);
   695→    domainResults.push({
   696→      domain,
   697→      passed: domainInfo?.passed ?? 0,
   698→      failed: domainInfo?.failed ?? 0,
   699→      cleanup,
   700→    });
   701→  }
   702→
   703→  const result: TestSuiteResult = {
   704→    startTime,
   705→    endTime,
   706→    durationMs: endTime.getTime() - startTime.getTime(),
   707→    coverage,
   708→    domainResults,
   709→    manifestPath: 'output/manifest.jsonl',
   710→    sessionLogsPath: 'output/sessions/',
   711→  };
   712→
   713→  console.log('[harness] Test suite complete');
   714→  console.log(`[harness] Coverage: ${coverage.coverage.toFixed(1)}%`);
   715→  console.log(`[harness] Passed: ${coverage.passedTools}, Failed: ${coverage.failedTools}`);
   716→
   717→  return result;
   718→}
