   746→  const queueItem: TestQueueItem = {
   747→    tool,
   748→    priority: 0,
   749→    prerequisites: [],
   750→    addedAt: new Date(),
   751→  };
   752→
   753→  await pool.acquire();
   754→  const testResult = await runTest(queueItem, sessionRunner, coordinator, manifest, tracker, pool, sharedContext, tool.domain);
   755→  const durationMs = Date.now() - startTime;
   756→
   757→  // Get the actual session result from the manifest
   758→  const history = await manifest.getToolHistory(toolName);
   759→  const latestEntry = history.length > 0 ? history[history.length - 1] : null;
