   823→/**
   824→ * Parse CLI arguments (T052)
   825→ */
   826→function parseArgs(args: string[]): CLIOptions {
   827→  const options: CLIOptions = {
   828→    command: 'help',
   829→  };
   830→
   831→  // Determine command
   832→  if (args.includes('--help') || args.includes('-h') || args.length === 0) {
   833→    options.command = 'help';
   834→  } else if (args.includes('--all') || args[0] === 'test:all') {
   835→    options.command = 'test';
   836→    options.all = true;
   837→  } else if (args.includes('--domain') || args[0] === 'test:domain') {
   838→    options.command = 'test';
   839→    const domainIdx = args.indexOf('--domain');
   840→    if (domainIdx !== -1 && args[domainIdx + 1]) {
   841→      options.domain = args[domainIdx + 1];
   842→    } else if (args[1]) {
   843→      options.domain = args[1];
   844→    }
   845→  } else if (args.includes('--tool') || args[0] === 'test:tool') {
   846→    options.command = 'test';
   847→    const toolIdx = args.indexOf('--tool');
   848→    if (toolIdx !== -1 && args[toolIdx + 1]) {
   849→      options.tool = args[toolIdx + 1];
   850→    } else if (args[1]) {
   851→      options.tool = args[1];
   852→    }
   853→  } else if (args[0] === 'coverage') {
   854→    options.command = 'coverage';
   855→  } else if (args[0] === 'cleanup') {
   856→    options.command = 'cleanup';
   857→    if (args.includes('--all')) {
   858→      options.all = true;
   859→    } else if (args.includes('--domain')) {
   860→      const domainIdx = args.indexOf('--domain');
   861→      if (domainIdx !== -1 && args[domainIdx + 1]) {
   862→        options.domain = args[domainIdx + 1];
   863→      }
   864→    } else if (args[1] && !args[1].startsWith('--')) {
   865→      options.domain = args[1];
   866→    }
   867→  } else if (args[0] === 'status') {
   868→    options.command = 'status';
   869→  } else if (args[0] === 'list-resources') {
   870→    options.command = 'list-resources';
   871→    options.orphaned = args.includes('--orphaned');
   872→  }
   873→
   874→  // Parse common options
   875→  options.cleanRoom = args.includes('--clean-room');
   876→  options.skipCleanup = args.includes('--skip-cleanup');
   877→
   878→  const concurrencyIdx = args.indexOf('--concurrency');
   879→  if (concurrencyIdx !== -1 && args[concurrencyIdx + 1]) {
   880→    options.concurrency = parseInt(args[concurrencyIdx + 1], 10);
   881→  }
   882→
   883→  return options;
   884→}
