import { handleDomainVirtualhostListCli } from '../../../../handlers/tools/mittwald-cli/domain/virtualhost-list-cli.js';
const tool = {
    name: 'mittwald_domain_virtualhost_list',
    title: 'List Virtual Hosts',
    description: 'List domain virtualhosts.',
    inputSchema: {
        type: 'object',
        properties: {
            projectId: {
                type: 'string',
                description: 'ID or short ID of a project; this argument is optional if a default project is set in the context'
            },
            all: {
                type: 'boolean',
                description: 'Show all virtualhosts across all projects'
            },
            output: {
                type: 'string',
                enum: ['txt', 'json', 'yaml', 'csv', 'tsv'],
                description: 'Output format (txt, json, yaml, csv, tsv)'
            },
            extended: {
                type: 'boolean',
                description: 'Show extended information'
            },
            noHeader: {
                type: 'boolean',
                description: 'Omit header row'
            },
            noTruncate: {
                type: 'boolean',
                description: 'Do not truncate output'
            },
            noRelativeDates: {
                type: 'boolean',
                description: 'Show absolute dates instead of relative dates'
            },
            csvSeparator: {
                type: 'string',
                enum: [',', ';'],
                description: 'CSV separator character'
            }
        },
        required: ["projectId"]
    }
};
const registration = {
    tool,
    handler: handleDomainVirtualhostListCli,
    schema: tool.inputSchema
};
export default registration;
// Legacy export for backwards compatibility
export const mittwald_domain_virtualhost_list_cli = tool;
//# sourceMappingURL=virtualhost-list-cli.js.map

