#!/usr/bin/env node
/**
 * Test virtualhost_list with invalid parameters
 * This is a simple test to verify error handling
 */

import { runSingleTool } from './src/harness/index.js';

async function testInvalidParams() {
  console.log('Testing mittwald_domain_virtualhost_list with invalid scenarios...\n');

  try {
    // Test with clean-room mode - tool must discover projectId itself
    console.log('Test: Clean-room mode (no pre-created resources)');
    const result = await runSingleTool('mcp__mittwald__mittwald_domain_virtualhost_list', true);

    console.log('\nResult:');
    console.log('  Status:', result.status);
    console.log('  Duration:', result.metrics.durationMs, 'ms');
    console.log('  Error:', result.error || 'none');

  } catch (error) {
    console.error('Error:', error);
  }
}

testInvalidParams();

